/* 图片风格：纸张纹理背景（SVG） */
.resume-renderer {
  position: relative;
}

.resume-renderer::before {
  content: '';
  position: absolute;
  inset: 0;
  background-image: url("data:image/svg+xml,%3Csvg%20xmlns%3D%27http%3A//www.w3.org/2000/svg%27%20width%3D%27120%27%20height%3D%27120%27%20viewBox%3D%270%200%20120%20120%27%3E%3Crect%20width%3D%27120%27%20height%3D%27120%27%20fill%3D%27%23ffffff%27/%3E%3Cpath%20d%3D%27M0%2030%20H120%20M0%2060%20H120%20M0%2090%20H120%27%20stroke%3D%27%239aa3b2%27%20stroke-width%3D%271%27%20opacity%3D%270.12%27/%3E%3Cpath%20d%3D%27M30%200%20V120%20M60%200%20V120%20M90%200%20V120%27%20stroke%3D%27%239aa3b2%27%20stroke-width%3D%271%27%20opacity%3D%270.08%27/%3E%3C/svg%3E");
  opacity: 0.42;
  pointer-events: none;
}

.resume-renderer .resume-layout,
.resume-renderer .resume-content {
  position: relative;
  z-index: 1;
}

/* 顶部横幅“图片”背景（SVG） */
.resume-renderer .basic-banner {
  color: #ffffff;
  border-radius: 16px;
  background-image: url("data:image/svg+xml,%3Csvg%20xmlns%3D%27http%3A//www.w3.org/2000/svg%27%20width%3D%27800%27%20height%3D%27180%27%20viewBox%3D%270%200%20800%20180%27%3E%3Cdefs%3E%3ClinearGradient%20id%3D%27g%27%20x1%3D%270%27%20y1%3D%270%27%20x2%3D%271%27%20y2%3D%271%27%3E%3Cstop%20offset%3D%270%27%20stop-color%3D%27%230f3d7a%27/%3E%3Cstop%20offset%3D%271%27%20stop-color%3D%27%232563eb%27/%3E%3C/linearGradient%3E%3C/defs%3E%3Crect%20width%3D%27800%27%20height%3D%27180%27%20fill%3D%27url(%23g)%27/%3E%3Ccircle%20cx%3D%27630%27%20cy%3D%2740%27%20r%3D%27120%27%20fill%3D%27%23ffffff%27%20fill-opacity%3D%270.08%27/%3E%3Ccircle%20cx%3D%27740%27%20cy%3D%27110%27%20r%3D%2790%27%20fill%3D%27%23ffffff%27%20fill-opacity%3D%270.06%27/%3E%3Cpath%20d%3D%27M0%20140%20C160%20110%20280%20180%20420%20145%20C560%20110%20660%20130%20800%20105%20L800%20180%20L0%20180%20Z%27%20fill%3D%27%23ffffff%27%20fill-opacity%3D%270.10%27/%3E%3C/svg%3E");
  background-size: cover;
  background-position: center;
  box-shadow: 0 10px 24px rgba(9, 31, 63, 0.16);
  border: 1px solid rgba(255, 255, 255, 0.22);
}

.resume-renderer .basic-banner .basic-name {
  color: #ffffff;
}

.resume-renderer .basic-banner .basic-title,
.resume-renderer .basic-banner .basic-subtitle,
.resume-renderer .basic-banner .basic-meta-item,
.resume-renderer .basic-banner .basic-contact-item {
  color: rgba(255, 255, 255, 0.90);
}

.resume-renderer .basic-avatar {
  border: 2px solid rgba(255, 255, 255, 0.72);
  background: rgba(255, 255, 255, 0.10);
}

/* 模块标题：统一左侧图标位 */
.resume-renderer .section-title {
  position: relative;
  padding-left: 34px;
  border-bottom: none;
}

.resume-renderer .section-title::before {
  content: '';
  position: absolute;
  left: 0;
  top: 50%;
  transform: translateY(-50%);
  width: 22px;
  height: 22px;
  background-size: 22px 22px;
  background-repeat: no-repeat;
  background-position: center;
  filter: drop-shadow(0 1px 0 rgba(255,255,255,0.6));
}

/* 各模块图标（SVG data URI） */
